head.script:
scwin.strCurDate = $c.date.getServerDateTime("yyyyMMdd");// 서버를 기준으로 현재 날짜 반환
scwin.strYm = $c.date.addMonth(scwin.strCurDate, -1); //한달전

scwin.memJson = $c.data.getMemInfo();
scwin.loUpperLobranCd = $c.data.getMemInfo("loUpperLobranCd"); //상위물류점소코드
scwin.loUpperLobranNm = $c.data.getMemInfo("loUpperLobranNm"); //상위물류점소

if (scwin.loUpperLobranCd == null) scwin.loUpperLobranCd = "";

scwin.params = "";
scwin.drcrNo = "";
scwin.stdDt = "";
scwin.lobranCd = "";

scwin.tabIndex = 0;
scwin.addOption = 0; //신규추가0,특약추가1 

scwin.onpageload = function () {

    //차량보험료 청구/회수 현황 화면  파라미터
    scwin.params = $c.data.getParameter();

    ed_stdDt.setValue(scwin.strYm); // 초기값 셋팅

    scwin.drcrNo = scwin.params.drcrNo;
    scwin.stdDt = scwin.params.stdDt;
    scwin.lobranCd = scwin.params.lobranCd;

    //------------------------------------------------------------
    // 파라미터에 의한 오프레이션
    //------------------------------------------------------------
    if (!$c.gus.cfIsNull(scwin.drcrNo)) {
        ed_drcrNo.setValue(scwin.drcrNo);
    }

    if (!$c.gus.cfIsNull(scwin.stdDt)) {
        ed_stdDt.setValue(scwin.stdDt);
    }

    if (!$c.gus.cfIsNull(scwin.lobranCd)) {
        lc_lobranCd.setValue(scwin.lobranCd);
    }

    if (!$c.gus.cfIsNull(scwin.drcrNo) || !$c.gus.cfIsNull(scwin.stdDt) || !$c.gus.cfIsNull(scwin.lobranCd)) {
        scwin.btn_retrieve_onclick();
    }

    scwin.onloadComplete();
};

scwin.onloadComplete = function () {
    /*소속지사 setting*/
    sbm_lobran.action = "/ds.co.RetreiveLoBranCMD.do";
    $c.sbm.execute(sbm_lobran);

    /*grid 담보 setting*/
    sbm_pldg.action = "/cm.zz.RetrieveCodeCMD.do?grpCd=FS151";
    $c.sbm.execute(sbm_pldg);

    //공통코드
    const codeOptions = [
        { grpCd: "ZZ203", compID: "lc_posnClsCd" },      //차량구분
        { grpCd: "ZZ102", compID: "gr_insr:insrCoCd" },  //보험사
        { grpCd: "FS150", compID: "gr_insr:insrCd,gr_except:insrCd" },    //보험
        { grpCd: "FS153", compID: "gr_insr:completeCd" },//완료구분
        { grpCd: "FS152", compID: "gr_insr:compCd" },    //배상구분
    ];
    $c.data.setCommonCode(codeOptions);

};

// 점소 콤보(소속 지사)
scwin.sbm_lobran_submitdone = function () {

    //소속지사 세팅
    lc_lobranCd.setValue(scwin.loUpperLobranCd);

    lc_lobranCd.focus();
};

//============================
//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_OpenPopup = async function (disGubun, pCode, pName, pClose) {

    switch (disGubun) {
        // 협력업체 팝업
        case 1:
            udc_comCode_clnt.setSelectId("retrieveCarKindClntInfo");
            await udc_comCode_clnt.cfCommonPopUp(
                scwin.udc_comCode_clnt_callBackFunc,
                pCode,
                pName,
                pClose, null, null, null, null, null, null, null, null, null);
            break;

        // 차량팝업 (장비)
        case 2:
            udc_comCode_eq.setSelectId("retrieveKndVehclListInfo");
            await udc_comCode_eq.cfCommonPopUp(
                scwin.udc_comCode_eq_callBackFunc,
                pCode,
                pName,
                pClose, null, null, null, null, "LO", null, null, null, null);
            break;

        default:
            console.warn("f_OpenPopup: 정의되지 않은 disGubun ->", disGubun);
            break;
    }
}

/* ------------------------------------------------------------------ */
/*  scwin 이벤트 바인딩                                                  */
/* ------------------------------------------------------------------ */
// 차량(장비)
scwin.udc_comCode_eq_onclickEvent = function (e) {
    scwin.f_OpenPopup(2, ed_eqCd.getValue(), ed_eqNm.getValue(), "T");
}
scwin.udc_comCode_eq_onblurCodeEvent = function (e) {
    if (ed_eqCd.getValue() === "") {
        ed_eqNm.setValue("");
    } else {
        scwin.f_OpenPopup(2, ed_eqCd.getValue(), ed_eqNm.getValue(), "T");
    }
}
scwin.udc_comCode_eq_onviewchangeNameEvent = function (info) {
    if (ed_eqNm.getValue() === "") ed_eqCd.setValue("");
}

// 협력업체
scwin.udc_comCode_clnt_onclickEvent = function (e) {
    scwin.f_OpenPopup(1, ed_clntNo.getValue(), ed_clntNm.getValue(), "T");
}
scwin.udc_comCode_clnt_onblurCodeEvent = function (e) {
    if (ed_clntNo.getValue() === "") {
        ed_clntNm.setValue("");
    } else {
        scwin.f_OpenPopup(1, ed_clntNo.getValue(), ed_clntNm.getValue(), "T");
    }
}
scwin.udc_comCode_clnt_onviewchangeNameEvent = function (info) {
    if (ed_clntNm.getValue() === "") ed_clntNo.setValue("");
}

//차량pop callbaack
scwin.udc_comCode_eq_callBackFunc = function (rtnList) {

    $c.gus.cfSetReturnValue(rtnList, ed_eqCd, ed_eqNm);
};
//협력업체 pop callback
scwin.udc_comCode_clnt_callBackFunc = function (rtnList) {

    $c.gus.cfSetReturnValue(rtnList, ed_clntNo, ed_clntNm);
};

//장비리스트조회 조회
scwin.btn_retrieve_onclick = function (e) {

    //dataMap set..
    dma_queryCondition.set("stdDt", ed_stdDt.getValue());
    dma_queryCondition.set("lobranCd", lc_lobranCd.getValue());
    dma_queryCondition.set("posnClsCd", lc_posnClsCd.getValue());
    dma_queryCondition.set("eqCd", ed_eqCd.getValue());
    dma_queryCondition.set("drcrNo", ed_drcrNo.getValue());
    dma_queryCondition.set("clntNo", ed_clntNo.getValue());

    $c.sbm.execute(sbm_retrieve);
};

//장비리스트조회 조회callback
scwin.sbm_retrieve_submitdone = function () {

    let nCnt = ds_carInfo.getRowCount();

    if (nCnt == 0) {
        return;
    } else {
        gr_carInfo.setFocusedCell(0, 0);
        total.setValue(nCnt);
        scwin.f_retrieve2();
    }
};

//장비리스트조회 grid Click event
scwin.gr_carInfo_oncellclick = function (rowIndex, columnIndex, columnId) {

    scwin.f_retrieve2();
};

//장비보험조회/차량보험료조회
scwin.f_retrieve2 = function () {

    dma_queryCondition2.set("stdDt", ed_stdDt.getValue());
    dma_queryCondition2.set("drcrNo", ds_carInfo.getCellData(ds_carInfo.getRowPosition(), "drcrNo"));

    $c.sbm.execute(sbm_retrieve2); //tab1 (장비보험조회)
    $c.sbm.execute(sbm_retrieve3); //tab2 (차량보험료조회)
};

//장비보험조회 callback
scwin.sbm_retrieve2_submitdone = function () {

    //$c.sbm.execute(sbm_retrieve3); //tab2 (차량보험료조회)

    let carAmt = 0;
    let shipAmt = 0;
    let umbAmt = 0;
    let totAmt = 0;

    for (var i = 0; i < ds_insr.getRowCount(); i++) {
        const insrCd = ds_insr.getCellData(i, "insrCd");
        const insrAmt = parseFloat(ds_insr.getCellData(i, "insrAmt") || 0);

        if (insrCd == "01") {
            carAmt = carAmt + insrAmt;
        } else if (insrCd == "02") {
            shipAmt += insrAmt;
        } else if (insrCd == "03") {
            umbAmt += insrAmt;
        }
    }
    totAmt = carAmt + shipAmt + umbAmt;

    ed_carAmt.setValue(carAmt);
    ed_shipAmt.setValue(shipAmt);
    ed_umbAmt.setValue(umbAmt);
    ed_totAmt.setValue(totAmt);

    let nCnt = ds_insr.getRowCount();
    gr_insr.setFocusedCell(0, 0);
    total2.setValue(nCnt);
};

//grid onclick event.
scwin.gr_insr_oncellclick = function (rowIndex, columnIndex, columnId) {

    var mainYn = ds_insr.getCellData(rowIndex, "mainYn");
    gr_insr.setReadOnly("grid", false);

    switch (columnId) {
        case "insrCd": // 보험
            if (mainYn == 1) { // 편집 가능
                gr_insr.setReadOnly("grid", false);
            } else {
                gr_insr.setReadOnly("grid", true);
            }
            break;
        case "pldgCd": // 담보
            // 신규행일 때만 필터 처리, 수정된 행도 필터 처리
            if (ds_insr.getRowStatusValue(rowIndex) != 0) {
                if (mainYn == 1) {
                    scwin.addOption = 0;

                } else {
                    scwin.addOption = 1;
                }
            }
            break;
        default:
            break;
    }

    // -----------------------------------------------
    // RowStatus별 컬럼 편집 제어
    // -----------------------------------------------
    // 초기상태:0, 갱신:1, 삽입:2, 삭제:3, 삽입 후 삭제:4
    var rowStatus = ds_insr.getRowStatusValue(rowIndex);

    // 편집 가능 컬럼 목록
    var allCols = ["insrCoCd", "insrCd", "pldgCd", "insrStDt", "insrEndDt",
        "psnlAmt1", "psnlAmt2", "impsnlAmt", "insrAmt"];

    if (rowStatus == 0) {
        // 기존행 (가우스 RowStatus == 0) → 전체 편집 가능
        for (var i = 0; i < allCols.length; i++) {
            gr_insr.setCellReadOnly(rowIndex, allCols[i], false);
        }

    } else if (rowStatus == 2) {
        // 신규행 (가우스 RowStatus == 1)
        var baseCols = ["insrCoCd", "insrCd", "pldgCd", "insrStDt", "insrEndDt"];

        // 기본 컬럼 편집 가능
        for (var i = 0; i < baseCols.length; i++) {
            gr_insr.setCellReadOnly(rowIndex, baseCols[i], false); // 편집 가능
        }

        var insrCd = ds_insr.getCellData(rowIndex, "insrCd");
        var pldgCd = ds_insr.getCellData(rowIndex, "pldgCd");

        // insrCd == "01" && pldgCd == "01" or "02"
        if (insrCd == "01" && (pldgCd == "01" || pldgCd == "02")) {
            gr_insr.setCellReadOnly(rowIndex, "insrAmt", true);   // 편집 불가
            gr_insr.setCellReadOnly(rowIndex, "psnlAmt1", false);  // 편집 가능
            gr_insr.setCellReadOnly(rowIndex, "psnlAmt2", false);
            gr_insr.setCellReadOnly(rowIndex, "impsnlAmt", false);
        } else {
            gr_insr.setCellReadOnly(rowIndex, "insrAmt", false);  // 편집 가능
            gr_insr.setCellReadOnly(rowIndex, "psnlAmt1", true);   // 편집 불가
            gr_insr.setCellReadOnly(rowIndex, "psnlAmt2", true);
            gr_insr.setCellReadOnly(rowIndex, "impsnlAmt", true);
        }
    }
};

// 청구제외 조회 (차량보험료 조회 완료 후 호출)
scwin.f_retrieve3 = function () {
    let insrNo = ds_insr.getCellData(ds_insr.getRowPosition(), "insrNo");

    if ($c.util.isEmpty(insrNo)) return;

    dma_queryCondition3.set("insrNo", insrNo);
    $c.sbm.execute(sbm_retrieve4);
};

//차량보험료 조회 callback
scwin.sbm_retrieve3_submitdone = function () {
    scwin.f_retrieve3();

    let nCnt = ds_retrieve.getRowCount();
    gr_retrieve.setFocusedCell(nCnt > 0 ? nCnt - 1 : 0, 0);
    total3.setValue(nCnt);
};


//청구제외 grid callback
scwin.sbm_retrieve4_submitdone = function () {

    let nCnt = ds_except.getRowCount();
    gr_except.setFocusedCell(nCnt > 0 ? nCnt - 1 : 0, 0);
    total4.setValue(nCnt);
};

scwin.btn_addRow1_onclick = (e) => scwin.f_addRow("I");  //보험추가btn

scwin.btn_addRow3_onclick = (e) => scwin.f_addRow("S");  //특약추가btn

scwin.f_addRow_except = (e) => scwin.f_addRow("E");  //청구제외 행추가

//-------------------------------------------------------------------------
//  그리드추가 - 코드 적용
//-------------------------------------------------------------------------
scwin.f_addRow = function (data) {

    // I: 보험추가, S: 특약추가
    switch (data) {
        case 'I':
            if ($c.util.isEmpty(ds_carInfo.getCellData(ds_carInfo.getRowPosition(), "drcrNo"))) {
                $c.win.alert("차량보험료 등록 시 차대번호는 필수입니다." +
                    "\n공통-장비-장비관리에서 차대번호를 입력해주세요.");
                return;
            }
            else {

                let rowIndex = ds_insr.getRowCount();
                ds_insr.insertRow(rowIndex);
                gr_insr.setFocusedCell(rowIndex, 0);

                ds_insr.setCellData(rowIndex, "insrNo", "");
                ds_insr.setCellData(rowIndex, "pldgSeq", "");
                ds_insr.setCellData(rowIndex, "drcrNo", ds_carInfo.getCellData(ds_carInfo.getRowPosition(), "drcrNo"));
                ds_insr.setCellData(rowIndex, "insrCoCd", "DB");
                ds_insr.setCellData(rowIndex, "insrCd", "");
                ds_insr.setCellData(rowIndex, "pldgCd", "");
                ds_insr.setCellData(rowIndex, "insrStDt", "");
                ds_insr.setCellData(rowIndex, "insrEndDt", "");
                ds_insr.setCellData(rowIndex, "adptDays", 0);
                ds_insr.setCellData(rowIndex, "psnlAmt1", 0);
                ds_insr.setCellData(rowIndex, "psnlAmt2", 0);
                ds_insr.setCellData(rowIndex, "impsnlAmt", 0);
                ds_insr.setCellData(rowIndex, "insrAmt", 0);
                ds_insr.setCellData(rowIndex, "completeCd", "01");
                ds_insr.setCellData(rowIndex, "estTmnDt", "");
                ds_insr.setCellData(rowIndex, "dcsnTmnDt", "");
                ds_insr.setCellData(rowIndex, "tmnRefundAmt", 0);
                ds_insr.setCellData(rowIndex, "compCd", "");
                ds_insr.setCellData(rowIndex, "evidFilePath", "");
                ds_insr.setCellData(rowIndex, "calcFilePath", "");
                ds_insr.setCellData(rowIndex, "eqCd", ds_carInfo.getCellData(ds_carInfo.getRowPosition(), "eqCd"));
                ds_insr.setCellData(rowIndex, "lobranCd", ds_carInfo.getCellData(ds_carInfo.getRowPosition(), "lobranCd"));
                ds_insr.setCellData(rowIndex, "posnClsCd", ds_carInfo.getCellData(ds_carInfo.getRowPosition(), "posnClsCd"));
                ds_insr.setCellData(rowIndex, "mainYn", 1);

                scwin.addOption = 0;
            }

            break;

        case 'S':

            if (ds_insr.getRowCount() == 0) {
                $c.win.alert("특약추가는 보험 조회 후 가능합니다.");
                return;
            } else {

                let j = 0;

                // 1. 체크 + mainYn == 1 인 행 카운트
                for (var i = 0; i < ds_insr.getRowCount(); i++) {
                    if (ds_insr.getCellData(i, "chk") == "T" && ds_insr.getCellData(i, "mainYn") == 1) {
                        j++;
                    }
                }

                // 1개가 아니면 경고 후 체크 전부 해제
                if (j < 1 || j > 1) {
                    $c.win.alert("특약을 추가할 보험을 선택 후 특약추가 버튼을 클릭하세요");
                    for (var i = 0; i < ds_insr.getRowCount(); i++) {
                        if (ds_insr.getCellData(i, "chk") == "T") {
                            ds_insr.setCellData(i, "chk", "F");
                        }
                    }
                    return;

                } else {
                    let row = 0;

                    for (var i = 0; i < ds_insr.getRowCount(); i++) {
                        if (ds_insr.getCellData(i, "chk") == "T" && ds_insr.getCellData(i, "mainYn") == 1) {
                            row = i;
                        }
                    }

                    if (ds_insr.getCellData(row, "mainYn") != 1) {
                        $c.win.alert("특약을 추가할 보험을 선택 후 특약추가 버튼을 클릭하세요.");
                        return;
                    }

                    if (ds_insr.getCellData(row, "completeCd") != "01") {
                        $c.win.alert("갱신, 해지된 보험에는 특약을 추가할 수 없습니다.");
                        return;
                    }

                    if (ds_insr.getCellData(row, "insrCd") == "") {
                        $c.win.alert("보험 선택 후 특약을 추가해 주세요.");
                        gr_insr.setFocusCell("insrCd");
                        gr_insr.focus();
                        return;
                    }


                    let rowIndex = ds_insr.getRowCount();
                    ds_insr.insertRow(rowIndex);
                    gr_insr.setFocusedCell(rowIndex, 0);

                    ds_insr.setCellData(rowIndex, "insrNo", ds_insr.getCellData(row, "insrNo"));
                    ds_insr.setCellData(rowIndex, "pldgSeq", "");
                    ds_insr.setCellData(rowIndex, "drcrNo", ds_carInfo.getCellData(ds_carInfo.getRowPosition(), "drcrNo"));
                    ds_insr.setCellData(rowIndex, "insrCoCd", "DB");
                    ds_insr.setCellData(rowIndex, "insrCd", ds_insr.getCellData(row, "insrCd"));
                    ds_insr.setCellData(rowIndex, "pldgCd", "");
                    ds_insr.setCellData(rowIndex, "insrStDt", ds_insr.getCellData(row, "insrStDt"));
                    ds_insr.setCellData(rowIndex, "insrEndDt", ds_insr.getCellData(row, "insrEndDt"));
                    ds_insr.setCellData(rowIndex, "adptDays", 0);
                    ds_insr.setCellData(rowIndex, "psnlAmt1", 0);
                    ds_insr.setCellData(rowIndex, "psnlAmt2", 0);
                    ds_insr.setCellData(rowIndex, "impsnlAmt", 0);
                    ds_insr.setCellData(rowIndex, "insrAmt", 0);
                    ds_insr.setCellData(rowIndex, "completeCd", "01");
                    ds_insr.setCellData(rowIndex, "estTmnDt", "");
                    ds_insr.setCellData(rowIndex, "dcsnTmnDt", "");
                    ds_insr.setCellData(rowIndex, "tmnRefundAmt", 0);
                    ds_insr.setCellData(rowIndex, "compCd", "");
                    ds_insr.setCellData(rowIndex, "evidFilePath", "");
                    ds_insr.setCellData(rowIndex, "calcFilePath", "");
                    ds_insr.setCellData(rowIndex, "eqCd", ds_carInfo.getCellData(ds_carInfo.getRowPosition(), "eqCd"));
                    ds_insr.setCellData(rowIndex, "lobranCd", ds_carInfo.getCellData(ds_carInfo.getRowPosition(), "lobranCd"));
                    ds_insr.setCellData(rowIndex, "posnClsCd", ds_carInfo.getCellData(ds_carInfo.getRowPosition(), "posnClsCd"));
                    ds_insr.setCellData(rowIndex, "mainYn", 0);

                    ds_insr.setCellData(row, "chk", "F");

                    scwin.addOption = 1;
                }
            }

            break;

        // 청구제외 그리드 행추가
        case 'E':
            let rowIndex = ds_except.getRowCount();
            ds_except.insertRow(rowIndex);
            gr_except.setFocusedCell(rowIndex, 0);

            ds_except.setCellData(rowIndex, "insrNo", ds_insr.getCellData(ds_insr.getRowPosition(), "insrNo"));
            ds_except.setCellData(rowIndex, "insrCd", ds_insr.getCellData(ds_insr.getRowPosition(), "insrCd"));
            ds_except.setCellData(rowIndex, "exceptStDt", "");
            ds_except.setCellData(rowIndex, "exceptEndDt", "");
            ds_except.setCellData(rowIndex, "adptDays", 0);
            ds_except.setCellData(rowIndex, "exceptRsn", "");

            break;
    }

};

//파일 다운로드
scwin.resultDown_onclick = function (e) {

    let row = ds_insr.getRowPosition();
    let col = gr_insr.getColumnID();

    if (row < 0) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_056, ["첨부파일 행"]);
        return;
    }
    else {
        let fileName = "";
        let filePath = "";

        if (col == "evidFileNm") {
            fileName = ds_insr.getCellData(row, "evidFileNm");
            filePath = ds_insr.getCellData(row, "evidFilePath");

        } else if (col == "calcFileNm") {
            fileName = ds_insr.getCellData(row, "calcFileNm");
            filePath = ds_insr.getCellData(row, "calcFilePath");
        }

        if (filePath.trim().length == 0) {
            $c.win.alert("선택하신 " + (row + 1) + "행에 파일이 등록되어 있지 않습니다.");
        }
        else {
            if (filePath.indexOf(".") > 0) {
                fileName += filePath.substring(filePath.indexOf("."), filePath.indexOf(".") + 4);
                $c.gus.cfDownloadFile(fileName, filePath);
            }
        }
    }
};

//grid (gr_insr) focus kill event
scwin.gr_insr_onafteredit = function (rowIndex, columnIndex, value) {
    // 보험료 합계 로직. AS_IS 에서 동작 안하는데.
    let colid = gr_insr.getColumnID(columnIndex);

    switch (colid) {
        case "psnlAmt1":
        case "psnlAmt2":
        case "impsnlAmt":
            // parseInt 또는 parseFloat으로 숫자 변환 후 합산
            var psnlAmt1 = parseInt(ds_insr.getCellData(rowIndex, "psnlAmt1") || 0, 10);
            var psnlAmt2 = parseInt(ds_insr.getCellData(rowIndex, "psnlAmt2") || 0, 10);
            var impsnlAmt = parseInt(ds_insr.getCellData(rowIndex, "impsnlAmt") || 0, 10);

            ds_insr.setCellData(rowIndex, "insrAmt", psnlAmt1 + psnlAmt2 + impsnlAmt);
            break;

        case "pldgCd": // filter를 초기화하지 않을 경우, 기존 다른 row의 pldgCd 값에도 영향을 주어 값이 초기화될 수 있음
            ds_pldg.clearFilter();
            break;
    }
};

//컬럼 옮기게 할지 말지 처리.
scwin.gr_insr_onbeforecolumnmove = function (info) {
    switch (info.startColumnID) {
        case "chk":
        case "insrCoCd":
        case "insrCd":
        case "pldgCd":
            return false;
    }
    return true;
};


//차량보험료 등록 저장 (f_Save1)
scwin.btn_save_onclick = async function (e) {

    if (ds_insr.getRowCount() == 0) {
        $c.win.alert("저장할 차량보험료 내역이 없습니다.");
        return;
    }

    for (var i = 0; i < ds_insr.getRowCount(); i++) {

        if (!$c.gus.cfIsAfterDate(ds_insr.getCellData(i, "insrStDt").trim(), ds_insr.getCellData(i, "insrEndDt").trim())) {
            $c.gus.cfAlertMsg(MSG_CM_ERR_039);
            return;
        }

        if (ds_insr.getRowStatusValue(i) == 2) { //신규

            if (ds_insr.getCellData(i, "insrCd") == "01" && (ds_insr.getCellData(i, "pldgCd") == "01" || ds_insr.getCellData(i, "pldgCd") == "02")) {
                if (ds_insr.getCellData(i, "psnlAmt1") > 0 || ds_insr.getCellData(i, "psnlAmt2") > 0 || ds_insr.getCellData(i, "impsnlAmt") > 0) {
                    // parseInt 또는 parseFloat으로 숫자 변환 후 합산
                    var psnlAmt1 = parseInt(ds_insr.getCellData(i, "psnlAmt1") || 0, 10);
                    var psnlAmt2 = parseInt(ds_insr.getCellData(i, "psnlAmt2") || 0, 10);
                    var impsnlAmt = parseInt(ds_insr.getCellData(i, "impsnlAmt") || 0, 10);

                    ds_insr.setCellData(i, "insrAmt", psnlAmt1 + psnlAmt2 + impsnlAmt);
                }
            }

            if (ds_insr.getCellData(i, "compCd") != "") {
                if (ds_insr.getCellData(i, "insrCd") != "01" || (ds_insr.getCellData(i, "pldgCd") != "01" && ds_insr.getCellData(i, "pldgCd") != "02")) {
                    $c.win.alert("배상구분은 자동차보험(단기,일반)의 해지인 경우에 입력합니다.");
                    ds_insr.setCellData(i, "compCd", "");
                    return;
                }
            }
        }
    }

    //필수Validate
    if (await $c.gus.cfValidate([gr_insr])) {
        let confirm = await $c.win.confirm("저장하시겠습니까?")
        if (confirm) {
            $c.sbm.execute(sbm_save);
        }
    }
};

scwin.sbm_save_submitdone = async function (e) {
    // responseJSON에서 resultDataSet 추출
    var resultDataSet = e.responseJSON.resultDataSet;

    if (!resultDataSet || resultDataSet.length === 0) {
        return;
    }

    // 첫번째 행 = Result (성공/실패 여부)
    var result = resultDataSet[0];
    if (result.Msg === "SUCC") {
        // 성공
        await $c.gus.cfAlertMsg(MSG_CM_INF_001);	// 성공적으로 저장하였습니다
        scwin.f_retrieve2();
    }
};

//갱신 btn
scwin.btn_save3_onclick = async function (e) {

    let j = 0;

    for (var i = 0; i < ds_insr.getRowCount(); i++) {
        if (ds_insr.getCellData(i, "chk") == "T" && ds_insr.getCellData(i, "completeCd") == "01") {
            j++;
        }
    }

    if (j < 1) {
        $c.win.alert("갱신할 보험을 선택해 주세요. \n 신규 상태의 보험만 갱신이 가능합니다.");
        return;
    } else {

        for (var i = 0; i < ds_insr.getRowCount(); i++) {
            if (ds_insr.getCellData(i, "chk") == "T") {
                if (ds_insr.getCellData(i, "completeCd") != "01") {
                    $c.win.alert((i + 1) + "번째 데이터는 갱신 혹은 해지되었으므로, 갱신이 불가능합니다.");
                    return;
                }
            }
        }

        if (await $c.gus.cfValidate([gr_insr])) {

            let confirm = await $c.win.confirm("갱신하시겠습니까?")
            if (confirm) {
                $c.sbm.execute(sbm_save3);
            }
        }
    }
};

scwin.sbm_save3_submitdone = async function () {

    await $c.gus.cfAlertMsg(MSG_CM_INF_001);	// 성공적으로 저장하였습니다
    scwin.f_retrieve2();
};

