//청구제외 저장 btn
scwin.btn_save2_onclick = async function (e) {

    let carStDt = "";
    let carEndDt = "";
    let shipStDt = "";
    let shipEndDt = "";
    let umbStDt = "";
    let umbEndDt = "";

    if (ds_except.getModifiedIndex() == 0) {
        $c.win.alert("저장할 청구제외 내역이 없습니다.");
        return;
    }

    for (var i = 0; i < ds_insr.getRowCount(); i++) {

        if (ds_insr.getCellData(i, "insrCd") == "01" && ds_insr.getCellData(i, "mainYn") == 1 && ds_insr.getCellData(i, "completeCd") == "01") {
            carStDt = ds_insr.getCellData(i, "insrStDt");
            carEndDt = ds_insr.getCellData(i, "insrEndDt");
        } else if (ds_insr.getCellData(i, "insrCd") == "02" && ds_insr.getCellData(i, "mainYn") == 1 && ds_insr.getCellData(i, "completeCd") == "01") {
            shipStDt = ds_insr.getCellData(i, "insrStDt");
            shipEndDt = ds_insr.getCellData(i, "insrEndDt");
        } else if (ds_insr.getCellData(i, "insrCd") == "03" && ds_insr.getCellData(i, "mainYn") == 1 && ds_insr.getCellData(i, "completeCd") == "01") {
            umbStDt = ds_insr.getCellData(i, "insrStDt");
            umbEndDt = ds_insr.getCellData(i, "insrEndDt");
        }
    }

    for (var i = 0; i < ds_except.getRowCount(); i++) {

        if (!$c.gus.cfIsAfterDate(ds_except.getCellData(i, "exceptStDt").trim(), ds_except.getCellData(i, "exceptEndDt").trim())) {
            $c.gus.cfAlertMsg(MSG_CM_ERR_039);
            return;
        }

        // alert 표시용 번호
        let order = i + 1;
        if (ds_except.getCellData(i, "insrCd") == "01" && ds_except.getCellData(i, "exceptStDt") < carStDt) {
            $c.win.alert(order + "번째 행의 시작일자가 자동차 보험의 시작일자보다 빠릅니다.");
            return;
        }

        if (ds_except.getCellData(i, "insrCd") == "01" && ds_except.getCellData(i, "exceptEndDt") > carEndDt) {
            $c.win.alert(order + "번째 행의 종료일자가 자동차 보험의 종료일자보다 느립니다.");
            return;
        }

        if (ds_except.getCellData(i, "insrCd") == "02" && ds_except.getCellData(i, "exceptStDt") < shipStDt) {
            $c.win.alert(order + "번째 행의 시작일자가 적재물 보험의 시작일자보다 빠릅니다.");
            return;
        }

        if (ds_except.getCellData(i, "insrCd") == "02" && ds_except.getCellData(i, "exceptEndDt") > shipEndDt) {
            $c.win.alert(order + "번째 행의 시작일자가 적재물 보험의 종료일자보다 느립니다.");
            return;
        }

        if (ds_except.getCellData(i, "insrCd") == "03" && ds_except.getCellData(i, "exceptStDt") < umbStDt) {
            $c.win.alert(order + "번째 행의 시작일자가 엄브렐라 보험의 시작일자보다 빠릅니다.");
            return;
        }

        if (ds_except.getCellData(i, "insrCd") == "03" && ds_except.getCellData(i, "exceptEndDt") > umbEndDt) {
            $c.win.alert(order + "번째 행의 시작일자가 엄브렐라 보험의 종료일자보다 느립니다.");
            return;
        }

    }

    if (await $c.gus.cfValidate([gr_except])) {
        let confirm = await $c.win.confirm("저장하시겠습니까?")
        if (confirm) {
            $c.sbm.execute(sbm_save2);
        }
    }
};

scwin.sbm_save2_submitdone = async function (e) {
    await $c.gus.cfAlertMsg(MSG_CM_INF_001);	// 성공적으로 저장하였습니다
    scwin.f_retrieve3();
};

// 데이터 필터
scwin.filterPldg = function (rowIndex) {
    // 1. 초기화
    ds_pldg.clearFilter();

    let mainValue = ds_insr.getCellData(rowIndex, "insrCd");
    if ($c.util.isEmpty(mainValue)) mainValue = "null"; // 보험 입력 안된 경우에는 담보 데이터 빈값으로 보여주기 위함

    // 2. 필터링
    ds_pldg.setColumnFilter({
        type: "row",
        colIndex: "upperCd",
        key: mainValue,
        condition: "and"
    });
}

//그리드 gr_insr -> onKeyPress event처리
scwin.gr_insr_oneditkeydown = function (info) {

    let row = ds_insr.getRowPosition();
    let colid = gr_insr.getFocusedColumnID(row); // 현재 포커스된 컬럼 ID 반환
    let keyCode = info.keyCode;

    if (keyCode == "229") {

        if (colid == "psnlAmt1") {
            ds_insr.setCellData(row, "insrAmt", ds_insr.getCellData(row, "psnlAmt1") + ds_insr.getCellData(row, "psnlAmt2") + ds_insr.getCellData(row, "impsnlAmt"));
        } else if (colid == "psnlAmt2") {
            ds_insr.setCellData(row, "insrAmt", ds_insr.getCellData(row, "psnlAmt1") + ds_insr.getCellData(row, "psnlAmt2") + ds_insr.getCellData(row, "impsnlAmt"));
        } else if (colid == "impsnlAmt") {
            ds_insr.setCellData(row, "insrAmt", ds_insr.getCellData(row, "psnlAmt1") + ds_insr.getCellData(row, "psnlAmt2") + ds_insr.getCellData(row, "impsnlAmt"));
        }
    }
};

//grid(gr_retrieve) 차량보험료 조회 click event.
scwin.gr_retrieve_oncellclick = function (rowIndex, columnIndex, columnId) {

    switch (columnId) {
        case "calcFileNm":
            scwin.f_Download2();
            break;
    }
};

//-----------------------------------------------------------------------------
// 보험료 조회 탭 파일 Download
//-----------------------------------------------------------------------------
scwin.f_Download2 = function () {

    let row = ds_retrieve.getRowPosition();
    let col = gr_retrieve.getFocusedColumnID(row); // 현재 포커스 컬럼 ID

    if (col == "calcFileNm") { // 수기산출표
        let fileName = ds_retrieve.getCellData(row, "calcFileNm");
        let filePath = ds_retrieve.getCellData(row, "calcFilePath");

        if (filePath.indexOf(".") > 0) {
            fileName += filePath.substring(filePath.indexOf("."), filePath.indexOf(".") + 4);
            $c.gus.cfDownloadFile(fileName, filePath);
        }
    }
};

