//file Upload
scwin.fileUp = function () {

    let rowindex = ds_insr.getRowPosition();
    let columnId = gr_insr.getColumnID(rowindex);

    let argObject = new Object();

    if (columnId == "evidFileNm") {
        argObject.fileName = ds_insr.getCellData(rowindex, "evidFileNm");
        argObject.filePath = ds_insr.getCellData(rowindex, "evidFileSize");
    } else if (columnId == "calcFileNm") {
        argObject.fileName = ds_insr.getCellData(rowindex, "calcFileNm");
        argObject.filePath = ds_insr.getCellData(rowindex, "calcFileSize");
    }


    let argPath = "";
    let dialSize = "";
    argPath = "/ui/ds/fs/consignmgnt/fs_403_01_01p.xml";

    // 해당 팝업이 개발대상이 아니고, 이 기능은 disable 처리
    dialSize = "dialogWidth:800px; dialogHeight:400px; status:no; scroll:yes";

    let resultList = $c.win.openPopup(argPath, argObject, dialSize);

    if (resultList != null) {
        if (resultList[0] != "" && resultList[0] != "undefined") {
            if (columnId == "evidFileNm") {
                ds_insr.setCellData(rowindex, "evidFileNm", resultList[1]);
                ds_insr.setCellData(rowindex, "evidFilePath", resultList[0]);
                ds_insr.setCellData(rowindex, "evidFileSize", resultList[2]);
            } else if (columnId == "calcFileNm") {
                ds_insr.setCellData(rowindex, "calcFileNm", resultList[1]);
                ds_insr.setCellData(rowindex, "calcFilePath", resultList[0]);
                ds_insr.setCellData(rowindex, "calcFileSize", resultList[2]);
            }
        }
    }
};

// 차량보험료 등록 >> Row 별 청구제외 보험 조회
scwin.gr_insr_onrowindexchange = function (rowIndex, oldRow) {
    if (oldRow == -1) return;
    scwin.f_retrieve3();
};

// 담보 selectbox 필터링 처리. (보험 선택 후 필터링 하던걸 담보 선택 전 필터링으로 변경)
scwin.gr_insr_onbeforeedit = function (rowIndex, columnIndex, value) {
    if (gr_insr.getColumnID(columnIndex) === "pldgCd") {
        scwin.filterPldg(rowIndex); // 편집 진입 시점에 필터
    }
    return true;
};
